#include <stdio.h>
#include <errno.h>
#include <string.h>
#include <unistd.h>
void check_path(const char *path) {
    errno = 0;
    int rc = access(path, F_OK);
    if (rc == -1) {
        printf("%s: %s (errno=%d)\n", path, strerror(errno), errno);
    } else {
        printf("%s: exists\n", path);
    }
}
int main(void) {
    check_path("/tmp");
    check_path("/nonexistent_kf_path");
    check_path("/also/does/not/exist");
    return 0;
}

